        [HttpGet("{invoiceId:int}")]
        public async Task<IActionResult> GetInvoice(int invoiceId)
        {
            // Extract authenticated user claims
            var userId = User.FindFirstValue(ClaimTypes.NameIdentifier);
            var userTenantId = User.FindFirstValue("tenant_id");
            var userRole = User.FindFirstValue(ClaimTypes.Role);

            if (string.IsNullOrEmpty(userId) || string.IsNullOrEmpty(userTenantId))
            {
                return Unauthorized(new { error = "Invalid user identity. Missing required claims." });
            }

            // Validate role - only specific roles can access invoices
            var allowedRoles = new HashSet<string> { "Admin", "Manager", "Accountant", "Viewer" };
            if (string.IsNullOrEmpty(userRole) || !allowedRoles.Contains(userRole))
            {
                return Forbid();
            }

            // Fetch the resource
            var invoice = await _invoiceRepository.GetByIdAsync(invoiceId);

            if (invoice == null)
            {
                // Return 404 instead of 403 to avoid leaking existence of resources in other tenants
                return NotFound(new { error = "Invoice not found." });
            }

            // Tenant isolation check - ensure user can only access invoices within their tenant
            if (!string.Equals(invoice.TenantId, userTenantId, StringComparison.OrdinalIgnoreCase))
            {
                // Return 404 to prevent tenant enumeration attacks
                return NotFound(new { error = "Invoice not found." });
            }

            // Resource-level authorization: Viewers can only see their own invoices
            if (string.Equals(userRole, "Viewer", StringComparison.OrdinalIgnoreCase)
                && !string.Equals(invoice.CreatedByUserId, userId, StringComparison.OrdinalIgnoreCase))
            {
                return Forbid();
            }

            // Confidential invoice check - only Admin and Manager can view confidential invoices
            if (invoice.IsConfidential
                && !string.Equals(userRole, "Admin", StringComparison.OrdinalIgnoreCase)
                && !string.Equals(userRole, "Manager", StringComparison.OrdinalIgnoreCase))
            {
                return Forbid();
            }

            // Field-level authorization: build the response DTO with only the fields the user's role permits
            var dto = MapToDto(invoice, userRole, userId);

            return Ok(dto);
        }

        /// <summary>
        /// Maps an Invoice entity to a DTO, filtering fields based on the user's role.
        /// </summary>
        private static InvoiceDto MapToDto(Invoice invoice, string userRole, string userId)
        {
            var dto = new InvoiceDto
            {
                Id = invoice.Id,
                InvoiceNumber = invoice.InvoiceNumber,
                Amount = invoice.Amount,
                Status = invoice.Status,
                CustomerName = invoice.CustomerName,
                CreatedDate = invoice.CreatedDate,
                DueDate = invoice.DueDate
            };

            // Notes field: only Admin, Manager, and Accountant can see notes
            if (string.Equals(userRole, "Admin", StringComparison.OrdinalIgnoreCase)
                || string.Equals(userRole, "Manager", StringComparison.OrdinalIgnoreCase)
                || string.Equals(userRole, "Accountant", StringComparison.OrdinalIgnoreCase))
            {
                dto.Notes = invoice.Notes;
            }

